127	// ============================================================================
128	// Dispatch lifecycle — jjsodp_command_lifecycle (Operation Taxonomy in JJS0)
129	// ============================================================================
130	
131	/// Shared dispatch body: lock → load → call handler → persist → return output.
132	///
133	/// Per jjdk_sole_operator, every operation locks and persists unconditionally.
134	/// The handler returns output text on success — it has no knowledge of locks,
135	/// persistence, or commit messages.
136	fn zjjrm_dispatch_inner(
137	    cmd: &str,
138	    firemark: &crate::jjrf_favor::jjrf_Firemark,
139	    handler: impl FnOnce(&mut crate::jjrg_gallops::jjrg_Gallops) -> Result<String, String>,
140	) -> Result<CallToolResult, McpError> {
141	    use vvc::vvco_Output;
142	
143	    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
144	        Ok(l) => l,
145	        Err(e) => {
146	            return Ok(CallToolResult::error(vec![Content::text(
147	                format!("jjx {}: error: {}", cmd, e),
148	            )]));
149	        }
150	    };
151	
152	    let gallops_path = gallops_pathbuf();
153	    let mut gallops = match crate::jjrg_gallops::jjrg_Gallops::jjrg_load(&gallops_path) {
154	        Ok(g) => g,
155	        Err(e) => {
156	            return Ok(CallToolResult::error(vec![Content::text(
157	                format!("jjx {}: error loading Gallops: {}", cmd, e),
158	            )]));
159	        }
160	    };
161	
162	    let output = match handler(&mut gallops) {
163	        Ok(o) => o,
164	        Err(e) => {
165	            return Ok(CallToolResult::error(vec![Content::text(
166	                format!("jjx {}: error: {}", cmd, e),
167	            )]));
168	        }
169	    };
170	
171	    let mut persist_output = vvco_Output::buffer();
172	    match crate::jjri_io::jjri_persist(
173	        &lock,
174	        &gallops,
175	        &gallops_path,
176	        firemark,
177	        format!("jjx: {}", cmd),
178	        50000,
179	        &mut persist_output,
180	    ) {
181	        Ok(_hash) => {}
182	        Err(e) => {
183	            return Ok(CallToolResult::error(vec![Content::text(
184	                format!("jjx {}: error: {}", cmd, e),
185	            )]));
186	        }
187	    }
188	
189	    Ok(CallToolResult::success(vec![Content::text(output)]))
190	}
191	
