const JJRM_CMD_NAME_SEARCH: &str = "jjx_search";
const JJRM_CMD_NAME_BRIEF: &str = "jjx_brief";
const JJRM_CMD_NAME_CORONETS: &str = "jjx_coronets";
const JJRM_CMD_NAME_PADDOCK: &str = "jjx_paddock";
