438	/// Reap stale officium directories by heartbeat mtime.
439	/// Returns (reaped_count, active_count) for summary reporting.
440	fn zjjrm_exsanguinate(officia: &Path) -> (usize, usize) {
441	    let entries = match std::fs::read_dir(officia) {
442	        Ok(e) => e,
443	        Err(_) => return (0, 0),
444	    };
445	    let now = std::time::SystemTime::now();
446	    let mut reaped: usize = 0;
447	    let mut active: usize = 0;
448	    for entry in entries.flatten() {
449	        let path = entry.path();
450	        if !path.is_dir() { continue; }
451	        let dir_name = match path.file_name() {
452	            Some(n) => n.to_string_lossy().to_string(),
453	            None => continue,
454	        };
455	        if dir_name.starts_with('.') { continue; }
456	        let heartbeat = path.join(HEARTBEAT_FILE);
457	        if !heartbeat.exists() {
458	            // No heartbeat file — legacy or corrupt. Log warning, skip.
459	            eprintln!("jjx exsanguinate: no heartbeat in {:?}, skipping", path.file_name());
460	            continue;
461	        }
462	        let mtime = match heartbeat.metadata().and_then(|m| m.modified()) {
463	            Ok(t) => t,
464	            Err(_) => continue,
465	        };
466	        let age = match now.duration_since(mtime) {
467	            Ok(d) => d,
468	            Err(_) => continue,
469	        };
470	        if age.as_secs() > EXSANGUINATION_THRESHOLD_SECS {
471	            if let Err(e) = std::fs::remove_dir_all(&path) {
472	                eprintln!("jjx exsanguinate: failed to remove {:?}: {}", path.file_name(), e);
473	            } else {
474	                reaped += 1;
475	            }
476	        } else {
477	            active += 1;
478	        }
479	    }
480	    (reaped, active)
481	}
