483	/// Generate officium ID: YYMMDD-NNNN (autonumber from directory listing).
484	fn zjjrm_generate_officium_id(officia: &Path, today: &str) -> String {
485	    let prefix = format!("{}-", today);
486	    let mut max_num: u32 = 999;
487	    if let Ok(entries) = std::fs::read_dir(officia) {
488	        for entry in entries.flatten() {
489	            let name = entry.file_name();
490	            let name = name.to_string_lossy();
491	            if let Some(suffix) = name.strip_prefix(&prefix) {
492	                if let Ok(num) = suffix.parse::<u32>() {
493	                    if num > max_num { max_num = num; }
494	                }
495	            }
496	        }
497	    }
498	    format!("{}{:04}", prefix, max_num + 1)
499	}
