536	/// Handle jjx_open: create a new officium.
537	async fn zjjrm_handle_open() -> Result<CallToolResult, McpError> {
538	    let cn = JJRM_CMD_NAME_OPEN;
539	    let mut output = vvc::vvco_Output::buffer();
540	
541	    // Disk space guard — block before any state changes
542	    match crate::jjrdk_diskcheck::jjrdk_check_disk_space() {
543	        Ok(survey) => vvco_out!(output, "{}", survey),
544	        Err(msg) => return Ok(CallToolResult::error(vec![Content::text(msg)])),
545	    }
546	
547	    let officia = PathBuf::from(OFFICIA_DIR);
548	    if let Err(e) = std::fs::create_dir_all(&officia) {
549	        return Ok(CallToolResult::error(vec![Content::text(
550	            format!("{}: error creating officia dir: {}", cn, e),
551	        )]));
552	    }
553	
554	    // Exsanguinate stale officia before creating new one
555	    let (reaped, active) = zjjrm_exsanguinate(&officia);
556	
557	    // Generate officium ID and atomically claim the exchange directory.
558	    // create_dir (not create_dir_all) fails with AlreadyExists if another
559	    // session raced to the same ID — retry with next autonumber.
560	    let today = chrono::Local::now().format("%y%m%d").to_string();
561	    let (id, exchange) = loop {
562	        let candidate = zjjrm_generate_officium_id(&officia, &today);
563	        let path = officia.join(&candidate);
564	        match std::fs::create_dir(&path) {
565	            Ok(()) => break (candidate, path),
566	            Err(e) if e.kind() == std::io::ErrorKind::AlreadyExists => continue,
567	            Err(e) => {
568	                return Ok(CallToolResult::error(vec![Content::text(
569	                    format!("{}: error creating exchange dir: {}", cn, e),
570	                )]));
571	            }
572	        }
573	    };
574	    // No gazette files created at open — they are ephemeral, single-MCP-call lifetime.
575	    std::fs::write(exchange.join(HEARTBEAT_FILE), b"").ok();
576	
577	    // Daily probe: run vvcp_probe if .probe_date doesn't match today
578	    let probe_date_path = officia.join(PROBE_DATE_FILE);
579	    let probe_data = if zjjrm_needs_probe(&probe_date_path, &today) {
580	        match vvc::vvcp_probe().await {
581	            Ok(data) => {
582	                std::fs::write(&probe_date_path, &today).ok();
583	                Some(data)
584	            }
585	            Err(e) => {
586	                eprintln!("{}: probe warning: {}", cn, e);
587	                None
588	            }
589	        }
590	    } else {
591	        None
592	    };
593	
594	    // Invitatory commit: jjb:BRAND::i: OFFICIUM <id>
595	    let brand = vvc::vvcc_get_brand();
596	    let subject = format!("OFFICIUM {}", id);
597	    let action = crate::jjrnm_markers::JJRNM_INVITATORY.to_string();
598	    let message = vvc::vvcc_format_branded(
599	        crate::jjrn_notch::JJRN_COMMIT_PREFIX,
600	        &brand,
601	        "",
602	        &action,
603	        &subject,
604	        probe_data.as_deref(),
605	    );
606	
607	    let commit_args = vvc::vvcc_CommitArgs {
608	        prefix: None,
609	        message: Some(message),
610	        allow_empty: true,
611	        no_stage: true,
612	        size_limit: vvc::VVCG_SIZE_LIMIT,
613	        warn_limit: vvc::VVCG_WARN_LIMIT,
614	    };
615	
616	    match vvc::vvcc_CommitLock::vvcc_acquire() {
617	        Ok(lock) => {
618	            let mut commit_output = vvc::vvco_Output::buffer();
619	            if let Err(e) = lock.vvcc_commit(&commit_args, &mut commit_output) {
620	                return Ok(CallToolResult::error(vec![Content::text(
621	                    format!("{}: invitatory commit error: {}", cn, e),
622	                )]));
623	            }
624	        }
625	        Err(e) => {
626	            return Ok(CallToolResult::error(vec![Content::text(
627	                format!("{}: lock error: {}", cn, e),
628	            )]));
629	        }
630	    };
631	
632	    if reaped > 0 || active > 0 {
633	        vvco_out!(output, "Exsanguination: {} active, {} reaped", active, reaped);
634	    }
635	    vvco_out!(output, "{}{}", OFFICIUM_SUN_PREFIX, id);
636	    Ok(CallToolResult::success(vec![Content::text(output.vvco_finish())]))
637	}
