    use crate::jjtu_testdir::JjkTestDir;
    use std::collections::BTreeMap;

    #[test]
    fn test_nominate_appends_to_heat_order() {
        let td = JjkTestDir::new("jjk_test_nominate_appends_to_heat_order");

