    message: jjrn_format_heat_message(&firemark, jjrn_HeatAction::Retire, &result.silks),
    size_limit: args.size_limit.unwrap_or(vvc::VVCG_SIZE_LIMIT),
    warn_limit: vvc::VVCG_WARN_LIMIT,
};

